option.value:
/* Reset / Base */

* {
    box-sizing: border-box;
}

html {
    scroll-behavior: smooth;
}

body {
    margin: 0;
    font-family: Arial, Helvetica, sans-serif;
    line-height: 1.6;
    background-color: #f5f7fb;
    color: #1f2937;
}

/* Hero */

.hero {
    background: linear-gradient(135deg, #1f3c88, #3b82f6);
    color: white;
    padding: 70px 20px;
    text-align: center;
}

.hero-content {
    max-width: 800px;
    margin: 0 auto;
}

.eyebrow {
    text-transform: uppercase;
    letter-spacing: 2px;
    font-size: 0.85rem;
    margin-bottom: 10px;
    opacity: 0.9;
}

.hero h1 {
    margin: 0 0 10px;
    font-size: 2.5rem;
}

.hero-text {
    margin: 0 auto;
    max-width: 650px;
    font-size: 1.05rem;
}

/* Navigation */

nav {
    background-color: white;
    border-bottom: 1px solid #e5e7eb;
    position: sticky;
    top: 0;
    z-index: 10;
}

nav ul {
    list-style: none;
    display: flex;
    justify-content: center;
    gap: 10px;
    margin: 0;
    padding: 12px 20px;
}

nav a {
    display: block;
    padding: 10px 16px;
    text-decoration: none;
    color: #1f2937;
    font-weight: bold;
    border-radius: 8px;
    transition: background-color 0.2s ease, color 0.2s ease;
}

nav a:hover {
    background-color: #e8eefc;
    color: #1f3c88;
}

/* Main layout */

.content {
    max-width: 1000px;
    margin: 40px auto;
    padding: 0 20px;
}

.card {
    background-color: white;
    padding: 28px;
    margin-bottom: 24px;
    border-radius: 16px;
    box-shadow: 0 8px 24px rgba(15, 23, 42, 0.08);
}

.card h2 {
    margin-top: 0;
    color: #1f3c88;
}

/* Skills */

.skill-list {
    list-style: none;
    display: flex;
    flex-wrap: wrap;
    gap: 12px;
    padding: 0;
    margin: 0;
}

.skill-list li {
    background-color: #e8eefc;
    color: #1f3c88;
    padding: 10px 14px;
    border-radius: 999px;
    font-weight: bold;
}

/* Projects */

.project-grid {
    display: grid;
    grid-template-columns: repeat(3, 1fr);
    gap: 16px;
    margin: 24px 0;
}

.project-card {
    background-color: #f8fafc;
    border: 1px solid #e5e7eb;
    border-radius: 14px;
    padding: 20px;
    transition: transform 0.2s ease, box-shadow 0.2s ease;
}

.project-card:hover {
    transform: translateY(-3px);
    box-shadow: 0 10px 20px rgba(15, 23, 42, 0.08);
}

.project-card h3 {
    margin-top: 0;
    margin-bottom: 10px;
    color: #1f3c88;
}

.project-card p {
    margin-bottom: 0;
    color: #4b5563;
}

/* Button */

button {
    padding: 12px 18px;
    font-size: 16px;
    cursor: pointer;
    border: none;
    border-radius: 10px;
    background-color: #1f3c88;
    color: white;
    transition: background-color 0.2s ease, transform 0.2s ease;
}

button:hover {
    background-color: #16306f;
    transform: translateY(-1px);
}

/* Extra text */

.hidden-text {
    display: none;
    margin-top: 16px;
    padding: 16px;
    background-color: #f5f7fb;
    border-left: 4px solid #3b82f6;
    border-radius: 10px;
}

/* Footer */

footer {
    text-align: center;
    color: #6b7280;
    padding: 10px 20px 40px;
}

/* Responsive */

@media (max-width: 768px) {
    .hero {
        padding: 50px 20px;
    }

    .hero h1 {
        font-size: 2rem;
    }

    nav ul {
        flex-direction: column;
        align-items: stretch;
    }

    nav a {
        text-align: center;
    }

    .content {
        margin: 24px auto;
    }

    .card {
        padding: 22px;
    }

    .project-grid {
        grid-template-columns: 1fr;
    }
}

/* Landscape Smartphone Fix */
@media (orientation: landscape) and (max-width: 1024px) {
    nav ul {
        padding: 8px 20px;
        gap: 8px;
    }

    nav a {
        padding: 6px 12px;
        font-size: 14px;
    }
}

